    "P_MT_REPAIR_DESC": "\u0412\u043e\u0441\u0441\u0442\u0430\u043d\u0430\u0432\u043b\u0438\u0432\u0430\u0435\u0442 \u0443\u0441\u0442\u0430\u043d\u043e\u0432\u043a\u0443 (\u043e\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0443\u044e\u0449\u0438\u0435 \u0438\u043b\u0438 \u043f\u043e\u0432\u0440\u0435\u0436\u0434\u0451\u043d\u043d\u044b\u0435 \u0444\u0430\u0439\u043b\u044b, \u044f\u0440\u043b\u044b\u043a\u0438 \u0438 \u0437\u0430\u043f\u0438\u0441\u0438 \u0440\u0435\u0435\u0441\u0442\u0440\u0430).",
    "P_MT_REMOVE_DESC": "\u0423\u0434\u0430\u043b\u044f\u0435\u0442 MyOverlay \u0441 \u044d\u0442\u043e\u0433\u043e \u043a\u043e\u043c\u043f\u044c\u044e\u0442\u0435\u0440\u0430.",
    "P_RO_TITLE": "\u041f\u0430\u0440\u0430\u043c\u0435\u0442\u0440\u044b \u0443\u0434\u0430\u043b\u0435\u043d\u0438\u044f",
    "P_RO_DESC": "\u0412\u044b\u0431\u0435\u0440\u0438\u0442\u0435, \u0447\u0442\u043e \u0443\u0434\u0430\u043b\u0438\u0442\u044c.",
    "P_RO_EXPLAIN": "\u0423\u0434\u0430\u043b\u0435\u043d\u0438\u0435 \u0443\u0431\u0438\u0440\u0430\u0435\u0442 MyOverlay: \u043f\u0440\u0438\u043b\u043e\u0436\u0435\u043d\u0438\u0435, \u0435\u0433\u043e \u044f\u0440\u043b\u044b\u043a\u0438, \u043d\u0430\u0441\u0442\u0440\u043e\u0439\u043a\u0438 \u0438 \u0441\u043e\u0445\u0440\u0430\u043d\u0451\u043d\u043d\u044b\u0439 \u0432\u0445\u043e\u0434.",
    "P_RO_GCLOUD": "\u0422\u0430\u043a\u0436\u0435 \u0443\u0434\u0430\u043b\u0438\u0442\u044c Google Cloud SDK",
